class Pic{
    constructor(path, alt){
        this.path = path;
        this.alt = alt;
    }
}


class Game {
    constructor(name, type, desc, pics, url, buttonTitle){
        this.name = name;
        this.type = type;
        this.desc = desc;
        this.pics = pics;
        this.url = url;
        this.buttonTitle = buttonTitle;

    }
}



